document.addEventListener('DOMContentLoaded',function(){const forms=document.querySelectorAll('.multi-step');forms.forEach(function(form){const steps=form.querySelectorAll('.step');const progressSteps=form.querySelectorAll('.udt-progress-step');let currentStep=0;function showStep(index){steps.forEach((step,i)=>{step.style.display=i===index?'block':'none'});if(progressSteps.length){progressSteps.forEach((el,i)=>{el.classList.remove('active','completed');if(i<index)el.classList.add('completed');if(i===index)el.classList.add('active');})}
currentStep=index;window.scrollTo({top:form.offsetTop,behavior:'smooth'})}
showStep(currentStep);form.querySelectorAll('.next-btn').forEach(btn=>{btn.addEventListener('click',function(){const inputs=steps[currentStep].querySelectorAll('input[required], textarea[required], select[required]');let valid=!0;inputs.forEach(input=>{if(!input.value.trim())valid=!1});if(!valid){alert('Mohon lengkapi semua field yang wajib diisi.');return}
if(currentStep<steps.length-1)showStep(currentStep+1);})});form.querySelectorAll('.prev-btn').forEach(btn=>{btn.addEventListener('click',function(){if(currentStep>0)showStep(currentStep-1);})});form.addEventListener('submit',function(e){e.preventDefault();let isValid=!0,firstInvalidStep=null;steps.forEach((step,index)=>{const inputs=step.querySelectorAll('input[required], textarea[required], select[required]');inputs.forEach(input=>{if(!input.value.trim()){isValid=!1;if(firstInvalidStep===null)firstInvalidStep=index}})});if(!isValid){showStep(firstInvalidStep);alert('Mohon lengkapi semua field yang wajib diisi.');return}
function val(id){var el=form.querySelector('#'+id);return el?el.value.trim():''}
function formatDate(input){if(!input)return'-';const parts=input.split('-');if(parts.length!==3)return input;const d=new Date(parts[2],parts[1]-1,parts[0]);return d.toLocaleDateString("id-ID",{day:"numeric",month:"long",year:"numeric"})}
var lines=[];lines.push('📋 Formulir Undangan Pernikahan');lines.push('');lines.push('👰 Mempelai Wanita:');lines.push('Nama Lengkap: '+(val('udt_bride_full')||'-'));lines.push('Nama Panggilan: '+(val('udt_bride_nick')||'-'));lines.push('Putri Ke: '+(val('udt_bride_order')||'-'));lines.push('Bapak: '+(val('udt_bride_father')||'-'));lines.push('Ibu: '+(val('udt_bride_mother')||'-'));lines.push('');lines.push('🤵 Mempelai Pria:');lines.push('Nama Lengkap: '+(val('udt_groom_full')||'-'));lines.push('Nama Panggilan: '+(val('udt_groom_nick')||'-'));lines.push('Putra Ke: '+(val('udt_groom_order')||'-'));lines.push('Bapak: '+(val('udt_groom_father')||'-'));lines.push('Ibu: '+(val('udt_groom_mother')||'-'));lines.push('');lines.push('📅 Akad Nikah:');lines.push('Tanggal: '+formatDate(val('udt_akad_date')));lines.push('Pukul: '+(val('udt_akad_time')?val('udt_akad_time')+' '+(val('udt_akad_tz')||''):'-'));lines.push('Tempat: '+(val('udt_akad_place')||'-'));if(val('udt_akad_maps'))lines.push('Maps: '+val('udt_akad_maps'));lines.push('');lines.push('🎉 Resepsi:');lines.push('Tanggal: '+formatDate(val('udt_resepsi_date')));lines.push('Pukul: '+(val('udt_resepsi_time')?val('udt_resepsi_time')+' '+(val('udt_resepsi_tz')||''):'-'));lines.push('Tempat: '+(val('udt_resepsi_place')||'-'));if(val('udt_resepsi_maps'))lines.push('Maps: '+val('udt_resepsi_maps'));if(val('udt_inviter')){lines.push('');lines.push('Turut Mengundang:');lines.push(val('udt_inviter'))}
var text=lines.join('\n');var phone=(form.getAttribute('data-wa')||'6281911556555').replace(/\D/g,'');var url='https://wa.me/'+phone+'?text='+encodeURIComponent(text);window.open(url,'_blank')})})})
;